// Pylontech Battery Balancing v1.0
// Runs every 30s. Detects if balancing is needed (30 days since last).
// When active: monitors SOC, current, cell voltages for balanced state.
// Balanced = SOC>=100 && |current|<0.5A && cellDiff<0.02V for 20 continuous minutes.

var BALANCE_INTERVAL_DAYS = 30;
var STABLE_DURATION_MS = 20 * 60 * 1000; // 20 minutes
var MAX_CURRENT_A = 0.5;
var MAX_CELL_DIFF_V = 0.02;
var CYCLE_MS = 30000; // 30s inject cycle

// === READ STATE ===
var ha = global.get("homeassistant");
var states = (ha && ha.homeAssistant && ha.homeAssistant.states) || {};

var config = global.get("fve_config") || {};
var zakazPretoku = (global.get("fve_current_mode") || "") === "zakaz_pretoku";

// Battery data from MQTT sensors
var batSoc = parseFloat((states["sensor.battery_percent"] || {}).state) || 0;
var batSocPrecise = parseFloat((states["sensor.battery_soc_precise"] || {}).state);
if (isNaN(batSocPrecise)) batSocPrecise = batSoc; // fallback to system-level SOC
var batCurrent = parseFloat((states["sensor.battery_dc_current"] || {}).state);
var maxCellV = parseFloat((states["sensor.battery_max_cell_voltage"] || {}).state);
var minCellV = parseFloat((states["sensor.battery_min_cell_voltage"] || {}).state);

// Solar & price data
var solarPower = parseFloat((states["sensor.vyroba_fve"] || {}).state) || 0;
var isSolarHour = false;
var solarStartHour = config.solar_start_hour || 9;
var solarEndHour = config.solar_end_hour || 17;
var currentHour = new Date().getHours();
if (currentHour >= solarStartHour && currentHour < solarEndHour) isSolarHour = true;

// Indoor temp check for pump blocking
var indoorTemp = parseFloat((states["sensor.hp2551ae_pro_v2_1_0_indoor_temperature"] || {}).state) || 22;
var targetTemp = config.topeni_cilova_teplota || 23;

// === LAST BALANCED TIMESTAMP ===
var lastBalancedStr = msg.lastBalanced || "";
var lastBalancedMs = 0;
if (lastBalancedStr && lastBalancedStr !== "unknown" && lastBalancedStr !== "unavailable") {
    lastBalancedMs = new Date(lastBalancedStr).getTime();
}
var now = Date.now();
var daysSinceBalance = lastBalancedMs > 0 ? (now - lastBalancedMs) / (1000 * 60 * 60 * 24) : 999;

// === GLOBALS ===
var balancingNeeded = global.get("balancing_needed") || false;
var balancingActive = global.get("balancing_active") || false;
var stableMs = global.get("balancing_stable_ms") || 0;

// === STEP 1: Check if balancing is needed ===
if (daysSinceBalance >= BALANCE_INTERVAL_DAYS) {
    balancingNeeded = true;
} else {
    balancingNeeded = false;
    // If not needed anymore (e.g. manual reset), deactivate
    if (balancingActive) {
        balancingActive = false;
        stableMs = 0;
    }
}

// === STEP 2: Activate balancing when conditions are right ===
if (balancingNeeded && !balancingActive && !zakazPretoku) {
    // Activate during solar hours with decent production
    if (isSolarHour && solarPower > 1000) {
        balancingActive = true;
        node.warn("Battery balancing ACTIVATED (solar: " + solarPower + "W)");
    }
    // Or during any hour if solar is not available (will use cheapest grid via orchestrator)
    // But only start if it's a cheap hour (orchestrator will handle this)
    // We activate and let orchestrator decide NABIJET vs SETRIT per hour
    else if (!isSolarHour && daysSinceBalance >= BALANCE_INTERVAL_DAYS + 1) {
        // Wait 1 extra day past deadline before using grid (give solar a chance first)
        balancingActive = true;
        node.warn("Battery balancing ACTIVATED (grid fallback, " + Math.round(daysSinceBalance) + " days)");
    }
}

// === STEP 3: Monitor balanced state ===
var balanced = false;
var statusReason = "";

if (balancingActive) {
    // Disable during zakaz pretoku (would limit solar production)
    if (zakazPretoku) {
        balancingActive = false;
        stableMs = 0;
        statusReason = "Pozastaveno (zákaz přetoků)";
    } else {
        // Check balanced conditions
        var socOk = batSocPrecise >= 100;
        var currentOk = !isNaN(batCurrent) && Math.abs(batCurrent) < MAX_CURRENT_A;
        // Cell voltage check - optional (sensor might be unavailable)
        var cellDiff = (!isNaN(maxCellV) && !isNaN(minCellV)) ? Math.abs(maxCellV - minCellV) : -1;
        var cellOk = cellDiff < 0 || cellDiff < MAX_CELL_DIFF_V; // -1 = unavailable = skip check

        if (socOk && currentOk && cellOk) {
            stableMs += CYCLE_MS;
            statusReason = "Stabilizace: " + Math.round(stableMs / 1000) + "s / " + (STABLE_DURATION_MS / 1000) + "s";
            if (stableMs >= STABLE_DURATION_MS) {
                balanced = true;
                statusReason = "VYBALANCOVÁNO!";
            }
        } else {
            stableMs = 0;
            var reasons = [];
            if (!socOk) reasons.push("SOC=" + batSocPrecise + "%");
            if (!currentOk) reasons.push("I=" + (isNaN(batCurrent) ? "N/A" : batCurrent.toFixed(2)) + "A");
            if (cellDiff >= 0 && !cellOk) reasons.push("cellDiff=" + cellDiff.toFixed(3) + "V");
            statusReason = "Čekám: " + reasons.join(", ");
        }
    }
} else if (balancingNeeded) {
    statusReason = "Potřeba bal. (" + Math.round(daysSinceBalance) + "d), čekám na podmínky";
} else {
    statusReason = "OK (" + Math.round(daysSinceBalance) + "d od posledního bal.)";
}

// === STEP 4: Handle balanced completion ===
var outputMsg = null;
if (balanced) {
    balancingActive = false;
    balancingNeeded = false;
    stableMs = 0;
    node.warn("Battery balancing COMPLETE!");
    // Send message to update HA entity
    outputMsg = {
        payload: {
            domain: "input_datetime",
            service: "set_datetime",
            data: {
                entity_id: "input_datetime.last_pylontech_balanced",
                datetime: new Date().toISOString().replace("T", " ").substring(0, 19)
            }
        }
    };
}

// === SAVE GLOBALS ===
global.set("balancing_needed", balancingNeeded);
global.set("balancing_active", balancingActive);
global.set("balancing_stable_ms", stableMs);

// Block pump during balancing (unless house is cold)
var blockPump = false;
if (balancingActive && indoorTemp >= (targetTemp - 0.2)) {
    blockPump = true;
}
global.set("balancing_block_pump", blockPump);

// Status for debug
var debugMsg = {
    payload: {
        balancingNeeded: balancingNeeded,
        balancingActive: balancingActive,
        daysSinceBalance: Math.round(daysSinceBalance * 10) / 10,
        stableMs: stableMs,
        blockPump: blockPump,
        batSocPrecise: batSocPrecise,
        batCurrent: batCurrent,
        maxCellV: maxCellV,
        minCellV: minCellV,
        cellDiff: (!isNaN(maxCellV) && !isNaN(minCellV)) ? Math.abs(maxCellV - minCellV) : null,
        status: statusReason
    }
};

return [outputMsg, debugMsg];
